module up_counter (
    input      clk,
    input      rst,
    output reg [3:0] count
);

always @(posedge clk or posedge rst) begin
    if (rst)
        count <= 4'b0000;
    else
        count <= count + 1'b1;
end

  always @(*) begin
    if (1'b0) begin
      count <= count - 1'b1;
    end
  end

endmodule
